@startuml
package javafx {
    class App {
        start()
        main()
    }
}

class InventoryController {
    ObservableList inventoryList
}

class Item {
    String name
    String serialNumber
    BigDecimal price
    get()
    set()
    toString()
}

class FileUtil {
    File file
    ObservableList list
    readFromTXT()
    readFromHTML()
    readFromJSON()
    readToTxt()
    readToHTML()
    readToJSON()
}

class FileLoader {
    readFromTXT()
    readFromHTML()
    readFromJSON()
}

class FileSaver {
    readToTxt()
    readToHTML()
    readToJSON()
}

App --* InventoryController : includes
InventoryController -- Item : contains
InventoryController -- FileUtil : contains
FileUtil --> FileLoader : extends
FileUtil --> FileSaver : extends
@enduml
